# --- Tool implementations returning different result shapes ---

def get_user(user_id: str) -> dict:
    user = db.find_user(user_id)
    if not user:
        return {"found": False, "user_id": user_id}
    return {"found": True, "id": user.id, "name": user.name, "email": user.email}

def list_orders(user_id: str) -> list:
    orders = db.get_orders(user_id)
    return [{"id": o.id, "total": o.total, "status": o.status} for o in orders]

def update_preference(user_id: str, key: str, value: str) -> dict:
    db.set_preference(user_id, key, value)
    return {"updated": True, "key": key, "value": value}

# --- Serialising results into tool_result blocks ---

def make_tool_result(tool_use_id: str, result, is_error: bool = False) -> dict:
    """Convert any result type to a valid tool_result block."""
    if isinstance(result, str):
        content = result
    elif isinstance(result, (dict, list, int, float, bool)) or result is None:
        content = json.dumps(result)
    else:
        content = str(result)
    return {
        "type": "tool_result",
        "tool_use_id": tool_use_id,
        "content": content,
        "is_error": is_error
    }

