from enum import Enum

class ToolErrorCode(str, Enum):
    NOT_FOUND       = "not_found"
    PERMISSION      = "permission_denied"
    INVALID_INPUT   = "invalid_input"
    RATE_LIMITED    = "rate_limited"
    UPSTREAM        = "upstream_error"
    TIMEOUT         = "timeout"

def structured_error(code: ToolErrorCode, message: str, retryable: bool = False) -> str:
    return json.dumps({
        "error": code.value,
        "message": message,
        "retryable": retryable
    })

# Examples
def delete_file(path: str) -> str:
    if not os.path.exists(path):
        return structured_error(ToolErrorCode.NOT_FOUND, f"File not found: {path}")
    if not os.access(path, os.W_OK):
        return structured_error(ToolErrorCode.PERMISSION, f"No write access: {path}")
    os.remove(path)
    return json.dumps({"deleted": True, "path": path})

