# Strategy: replace bulky tool results with summaries after use
# to keep the context window from growing unbounded.

def compress_tool_results(messages: list[dict], max_content_chars: int = 500) -> list[dict]:
    """Replace long tool_result content with a truncated summary."""
    compressed = []
    for msg in messages:
        if msg["role"] != "user":
            compressed.append(msg)
            continue
        content = msg["content"]
        if not isinstance(content, list):
            compressed.append(msg)
            continue
        new_content = []
        for block in content:
            if block.get("type") == "tool_result":
                text = block.get("content", "")
                if isinstance(text, str) and len(text) > max_content_chars:
                    block = {**block, "content": text[:max_content_chars] + " ... [truncated]"}
            new_content.append(block)
        compressed.append({**msg, "content": new_content})
    return compressed

# Use before each API call to prevent context bloat in long-running agents
messages = compress_tool_results(messages)

# Pattern: inject a hint when the result signals the agent should stop or redirect

def make_result_with_hint(tool_use_id: str, result: dict) -> dict:
    """Add an agent hint field to guide the next model step."""
    content = dict(result)

    if not result.get("found", True):
        content["_hint"] = "Item not found. Ask the user to confirm the identifier before trying another lookup."
    elif result.get("requires_confirmation"):
        content["_hint"] = "This action requires explicit user confirmation. Do not proceed without it."
    elif result.get("truncated"):
        content["_hint"] = "Result was truncated. Use the appropriate fetch-section tool if you need more detail."

    return {
        "type": "tool_result",
        "tool_use_id": tool_use_id,
        "content": json.dumps(content)
    }

import functools, time

# In-memory cache for read-only tool results that do not change frequently
_cache: dict[str, tuple[float, str]] = {}  # key -> (timestamp, serialised_result)
CACHE_TTL = 60.0   # seconds

def cached_tool(tool_name: str, input_dict: dict, fn) -> str:
    """Execute fn(**input_dict) and cache the result by (tool_name, stable key)."""
    # Only cache read-only tools — never cache mutation tools
    READ_ONLY_TOOLS = {"get_product", "search_catalogue", "get_exchange_rate"}
    if tool_name not in READ_ONLY_TOOLS:
        return json.dumps(fn(**input_dict))

    cache_key = tool_name + "|" + json.dumps(input_dict, sort_keys=True)
    entry = _cache.get(cache_key)
    now = time.monotonic()

    if entry and (now - entry[0]) < CACHE_TTL:
        return entry[1]   # return cached result

    result = json.dumps(fn(**input_dict))
    _cache[cache_key] = (now, result)
    return result

