from dataclasses import dataclass, field

@dataclass
class ToolCallRecord:
    turn: int
    tool_use_id: str
    tool_name: str
    input: dict
    output: str
    is_error: bool
    duration_ms: float

@dataclass
class AgentRunRecord:
    records: list[ToolCallRecord] = field(default_factory=list)

    def add(self, record: ToolCallRecord):
        self.records.append(record)

    def error_rate(self) -> float:
        if not self.records:
            return 0.0
        return sum(1 for r in self.records if r.is_error) / len(self.records)

    def slowest_tool(self) -> str | None:
        if not self.records:
            return None
        return max(self.records, key=lambda r: r.duration_ms).tool_name

    def summary(self) -> dict:
        return {
            "total_calls": len(self.records),
            "errors": sum(1 for r in self.records if r.is_error),
            "error_rate": round(self.error_rate(), 3),
            "tools_used": list({r.tool_name for r in self.records}),
            "slowest_tool": self.slowest_tool()
        }

